// Java: this compiles fine, crashes at runtime if user is null
// user.getName().toLowerCase()

// Kotlin: the TYPE tells you if null is possible
val user: User? = repo.findById(id)     // ? = nullable
val nameLen = user?.name?.length         // safe-call — if any step is null, whole thing is null
val nameLenOrZero = user?.name?.length ?: 0     // Elvis — default when null

// Force it (only when you're 100% sure):
val def = user!!.name       // !! — throws KotlinNullPointerException if null
// Rule: !! is a code smell. Use safe-call + Elvis instead.

// Late init when you must (like Android's onCreate):
lateinit var binding: ActivityMainBinding      // non-null but assigned later

// Java: full data class = 40+ lines of getters, setters, equals, hashCode, toString
// Kotlin: one line
data class User(val id: Int, val name: String, val email: String? = null)

// You get for free:
// - Constructor
// - Immutable properties (val = read-only) or mutable (var)
// - equals & hashCode based on ALL fields
// - toString: User(id=1, name=Ada, email=null)
// - copy() — create a modified copy: user.copy(email = "a@b.com")
// - Destructuring: val (id, name, _) = user

// Extend String — no subclassing, no util classes
fun String.isValidEmail(): Boolean = matches(Regex("[^@]+@[^\\.]+\\..+"))

// Extend Android View — hugely common in Android code
fun View.show() { visibility = View.VISIBLE }
fun View.hide() { visibility = View.GONE }

// Use it:
"user@example.com".isValidEmail()   // true
myButton.hide()                      // way better than myButton.setVisibility(View.GONE)

// Under the hood: compiles to a static function with the receiver as first parameter.
// So they're not really 'added' to the class — the compiler makes them look like they are.

// Old: nested callbacks / RxJava
repo.getUser(id) { user ->
  api.getFriends(user.id) { friends ->
    ui.show(friends)   // 3 levels deep already
  }
}

// Kotlin coroutines: sequential-looking, non-blocking
lifecycleScope.launch {
  val user    = repo.getUser(id)         // suspends without blocking a thread
  val friends = api.getFriends(user.id)  // resumes when done
  ui.show(friends)                       // flat!
}

// suspend fun = a function that CAN pause without blocking the thread
suspend fun getUser(id: Int): User = ...

