// File: UserApp.kt
// Run: kotlinc UserApp.kt -include-runtime -d UserApp.jar && java -jar UserApp.jar

data class User(val id: Int, val name: String, val email: String? = null)

fun String.isValidEmail(): Boolean = matches(Regex("[^@]+@[^.]+\\..+"))

fun findUser(id: Int, users: List<User>): User? = users.firstOrNull { it.id == id }

fun List<User>.withValidEmails() = filter { it.email?.isValidEmail() == true }

fun main() {
  val users = listOf(
    User(1, "Ada", "ada@example.com"),
    User(2, "Ben"),
    User(3, "Cara", "invalid-email"),
    User(4, "Dan", "dan@example.com"),
  )

  val user = findUser(2, users)
  println(user?.name ?: "not found")             // Ben

  val validEmailed = users.withValidEmails()
  println(validEmailed.map { it.name })          // [Ada, Dan]

  val updated = users[0].copy(email = "ada@newmail.com")
  println(updated)                                // User(id=1, name=Ada, email=ada@newmail.com)

  val (id, name, email) = updated
  println("$id / $name / $email")

  println("Total: ${users.size}, with valid emails: ${validEmailed.size}")
}

// Output:
//   Ben
//   [Ada, Dan]
//   User(id=1, name=Ada, email=ada@newmail.com)
//   1 / Ada / ada@newmail.com
//   Total: 4, with valid emails: 2
